#pragma once

#include "common.h"
#include "core.h"
#include "shared.h"
#include "instruction.h"
#include "state.h"

namespace via
{

// Machine code executable type
using ExecutableMachineCode = int (*)(void);

// Logically bound chunk of instructions
// Generated by the compiler
struct Chunk
{
    uint32_t pc = 0;
    // Pointer to the machine code of the chunk, function pointer
    ExecutableMachineCode mcode = nullptr;
    size_t mlen = 0;
};

} // namespace via